-- 1. what is the total revenue generated by male vs. female customers?
select gender, SUM(purchase_amount) as revenue
from customer
group by 1;

-- 2. which customers used a discount but still spent more than the average purchase amount?
select customer_id, purchase_amount from customer 
where discount_applied = 'Yes' and purchase_amount >= (select AVG(purchase_amount) from customer);

-- 3. which are the top 5 products with the highest average review rating?
select item_purchased, ROUND(AVG(review_rating::numeric),2) as avg_review_rating from customer
group by 1
order by 2 desc
limit 5;

-- 4. compare the average purchase amounts between standard and express shipping.
select shipping_type, ROUND(AVG(purchase_amount),2) as avg_purchase_amount from customer
where shipping_type in('Express', 'Standard')
group by 1;

-- 5. do subscribed customers spend more? Compare average spend 
--and total revenue between subscribers and non-subscribers.
select subscription_status, ROUND(AVG(purchase_amount),2) as avg_spend, ROUND(SUM(purchase_amount),2) as total_revenue,
count(customer_id) as total_customers
from customer
group by 1
order by 3, 2 desc;

-- 6. which 5 products have the highest percentage of purchases with discounts applied?
select item_purchased, Round((100 * sum(case when discount_applied = 'Yes' then 1 else 0 end) / count(*)),2) 
as discount_rate
from customer
group by 1
order by 2 desc
limit 5;

-- 7. segment customers into New, returning and loyal based on their total number of previous purchases, 
-- and show the count of each segment.
with customer_type as(
select customer_id, previous_purchases,
case 
when previous_purchases = 1 then 'New'
when previous_purchases between 2 and 10 then 'Returning'
else 'Loyal'
end as customer_segment
from customer
)
select customer_segment, count(*) as "Number of Customers" from customer_type
group by 1;

-- 8. what are the top three most purchased products within each category?
with item_counts as(
select category, item_purchased, count(customer_id) as total_orders,
ROW_NUMBER() over(partition by category order by count(customer_id) desc) as item_rank from customer group by 1, 2
)
select item_rank, category, item_purchased, total_orders from item_counts where item_rank <= 3;

-- 9. are customers who are repeat buyers (more than 5 previous purchases) also likely to subscribe?
select subscription_status, count(customer_id) as repeat_buyers from customer
where previous_purchases > 5
group by 1;

select * from customer limit 5;
-- 10. what is the revenue contribution of each age group?
select age_group, sum(purchase_amount) as total_revenue from customer
group by 1
order by 2 desc;